mapper.select:
SELECT u.userId, u.userName, d.deptName, u.position, 'USER' AS assignType FROM user_role ur JOIN user_info u ON ur.userId = u.userId LEFT JOIN dept_info d ON u.deptId = d.deptId WHERE ur.roleCode = #{roleCode}
UNION
SELECT u.userId, u.userName, d.deptName, u.position, 'DEPT' AS assignType FROM dept_role dr JOIN dept_info d ON dr.deptId = d.deptId JOIN user_info u ON u.deptId = d.deptId AND u.useYn = 'Y' WHERE dr.roleCode = #{roleCode}
ORDER BY userId
